def execute_tool(tool_name: str, tool_args: dict[str, Any]) -> str:
    # Requiere confirmación humana para herramientas de alto riesgo
    if tool_name in HIGH_RISK_TOOLS:
        print(f"\n⚠ El agente quiere ejecutar: {tool_name}")
        print(f"   Argumentos: {tool_args}")
        confirm = input("   ¿Confirmas? (s/N): ").strip().lower()
        if confirm != "s":
            return f"Acción '{tool_name}' cancelada por el usuario."

    # Ejecutar la herramienta solo si fue confirmada
    return dispatch_tool(tool_name, tool_args)

def dispatch_tool(name: str, args: dict) -> str:
    # Aquí iría la lógica real de cada herramienta
    return f"[{name} ejecutado con {args}]"

