import unicodedata
import re

def detect_adversarial_text(text: str) -> dict:
    issues = []
    # Caracteres de control invisibles
    control_chars = [c for c in text if unicodedata.category(c) in ('Cf', 'Cc', 'Co')]
    if control_chars:
        issues.append(f"Caracteres de control: {len(control_chars)}")
    # Homoglifos (cirílico, fullwidth)
    suspicious_ranges = [(0x0400, 0x04FF), (0xFF00, 0xFFEF), (0x2000, 0x206F)]
    for char in text:
        cp = ord(char)
        for start, end in suspicious_ranges:
            if start <= cp <= end:
                issues.append(f"Carácter sospechoso U+{cp:04X}")
                break
    if re.search(r'(\s{5,})', text):
        issues.append("Espaciado excesivo")
    return {
        "is_adversarial": len(issues) > 0,
        "issues": issues[:5],
        "clean_text": unicodedata.normalize('NFKC', text).strip()
    }

