import ast
import io
from contextlib import redirect_stdout

DANGEROUS_MODULES = {'os','sys','subprocess','shutil','socket','requests',
                      'urllib','http','pickle','importlib'}

def validate_ast(code: str) -> list[str]:
    issues = []
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return [f"Sintaxis inválida: {e}"]
    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            module = node.names[0].name if isinstance(node, ast.Import) else (node.module or '')
            if module.split('.')[0] in DANGEROUS_MODULES:
                issues.append(f"Import peligroso: {module}")
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in ('eval','exec','__import__'):
                issues.append(f"Llamada peligrosa: {node.func.id}()")
    return issues

def safe_execute(code: str) -> dict:
    issues = validate_ast(code)
    if issues:
        return {"success": False, "error": "Código rechazado", "issues": issues}
    buf = io.StringIO()
    safe_globals = {"__builtins__": {"print": print, "range": range, "len": len}}
    try:
        with redirect_stdout(buf):
            exec(compile(code, "<llm>", "exec"), safe_globals)
        return {"success": True, "output": buf.getvalue()}
    except Exception as e:
        return {"success": False, "error": str(e)}

