import json
import subprocess
import sys

def audit_dependencies() -> dict:
    report = {"safe": [], "vulnerable": [], "warnings": []}
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip_audit", "--format=json"],
            capture_output=True, text=True, timeout=60
        )
        audit_data = json.loads(result.stdout)
        for dep in audit_data.get("dependencies", []):
            if dep.get("vulns"):
                report["vulnerable"].append({
                    "package": dep["name"],
                    "version": dep["version"],
                    "vulns": [v["id"] for v in dep["vulns"]]
                })
            else:
                report["safe"].append(dep["name"])
    except FileNotFoundError:
        report["warnings"].append("pip-audit no instalado. Ejecuta: pip install pip-audit")
    except Exception as e:
        report["warnings"].append(str(e))
    return report

if __name__ == "__main__":
    result = audit_dependencies()
    if result["vulnerable"]:
        print("DEPENDENCIAS VULNERABLES:")
        for dep in result["vulnerable"]:
            print(f"  {dep['package']}=={dep['version']}: {dep['vulns']}")
        sys.exit(1)  # Fallar el pipeline de CI
    print(f"OK: {len(result['safe'])} dependencias sin CVEs conocidos")

import json

OUTPUT_SCHEMA = {
    "required_keys": {"action", "parameters", "confidence"},
    "allowed_actions": {"search", "summarize", "translate", "analyze"},
    "max_parameters": 5,
}

class LLMOutputValidationError(ValueError):
    pass

def validate_llm_json_output(raw_output: str) -> dict:
    try:
        data = json.loads(raw_output)
    except json.JSONDecodeError as e:
        raise LLMOutputValidationError(f"JSON inválido: {e}")
    if not isinstance(data, dict):
        raise LLMOutputValidationError("Output debe ser objeto JSON")
    missing = OUTPUT_SCHEMA["required_keys"] - set(data.keys())
    if missing:
        raise LLMOutputValidationError(f"Claves faltantes: {missing}")
    if data["action"] not in OUTPUT_SCHEMA["allowed_actions"]:
        raise LLMOutputValidationError(f"Acción no permitida: {data['action']}")
    if len(data.get("parameters", {})) > OUTPUT_SCHEMA["max_parameters"]:
        raise LLMOutputValidationError("Demasiados parámetros")
    # Retornar solo campos conocidos — nunca pasar campos extra downstream
    return {
        "action":     data["action"],
        "parameters": dict(list(data["parameters"].items())[:OUTPUT_SCHEMA["max_parameters"]]),
        "confidence": float(data["confidence"])
    }

raw = '{"action":"search","parameters":{"q":"test"},"confidence":0.9}'
