import ipaddress
import socket
from urllib.parse import urlparse
import requests

PRIVATE_RANGES = [
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
    ipaddress.ip_network("127.0.0.0/8"),
    ipaddress.ip_network("169.254.0.0/16"),  # AWS metadata
]

BLOCKED_HOSTS = {"169.254.169.254", "metadata.google.internal", "metadata.azure.com"}

def is_ssrf_target(url: str) -> bool:
    parsed = urlparse(url)
    hostname = parsed.hostname or ""
    if hostname in BLOCKED_HOSTS or hostname.endswith(".internal"):
        return True
    try:
        ip = ipaddress.ip_address(socket.gethostbyname(hostname))
        return any(ip in net for net in PRIVATE_RANGES)
    except Exception:
        return True  # si no se puede resolver, bloquear

def agent_fetch_url(url: str) -> str:
    if not url.startswith(("https://", "http://")):
        raise ValueError("Solo se permiten URLs HTTP/HTTPS")
    if is_ssrf_target(url):
        raise ValueError(f"URL bloqueada: {url}")
    response = requests.get(url, timeout=10, allow_redirects=False)
    response.raise_for_status()
    return response.text[:10000]

