from pathlib import Path

SANDBOX_ROOT = Path("/app/sandbox").resolve()
ALLOWED_EXTENSIONS = {".txt", ".md", ".csv", ".json", ".log"}
MAX_FILE_SIZE = 1 * 1024 * 1024  # 1 MB

def safe_read_file(user_provided_path: str) -> str:
    try:
        full_path = (SANDBOX_ROOT / user_provided_path).resolve()
    except Exception as e:
        raise PermissionError(f"Path inválido: {e}")
    # La única defensa fiable: verificar que el path resuelto empieza con el sandbox
    if not str(full_path).startswith(str(SANDBOX_ROOT)):
        raise PermissionError(f"Acceso denegado: fuera del sandbox")
    if not full_path.exists():
        raise FileNotFoundError(f"No encontrado: {full_path.name}")
    if full_path.suffix.lower() not in ALLOWED_EXTENSIONS:
        raise PermissionError(f"Extensión no permitida: {full_path.suffix}")
    if full_path.stat().st_size > MAX_FILE_SIZE:
        raise ValueError("Archivo demasiado grande")
    return full_path.read_text(encoding="utf-8", errors="replace")

