import re
import logging
from typing import Any

SENSITIVE_FIELDS = {"system_prompt","api_key","password","token","secret","authorization"}

PII_PATTERNS = [
    (r"\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b", "[EMAIL]"),
    (r"Bearer\s+[A-Za-z0-9\-._~+/]+=*", "Bearer [TOKEN]"),
    (r"sk-[A-Za-z0-9]{20,}", "[API_KEY]"),
]

def sanitize_for_log(obj: Any, max_length: int = 500) -> Any:
    if isinstance(obj, str):
        result = obj[:max_length]
        for pattern, replacement in PII_PATTERNS:
            result = re.sub(pattern, replacement, result)
        return result
    if isinstance(obj, dict):
        return {
            k: "[REDACTED]" if k.lower() in SENSITIVE_FIELDS
               else sanitize_for_log(v, max_length)
            for k, v in obj.items()
        }
    if isinstance(obj, list):
        return [sanitize_for_log(item, max_length) for item in obj]
    return obj

class SanitizingFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        if isinstance(record.msg, (dict, list, str)):
            record.msg = sanitize_for_log(record.msg)
        return super().format(record)

logger = logging.getLogger("vulnerai")
handler = logging.StreamHandler()
handler.setFormatter(SanitizingFormatter())
