import json
import hashlib
from datetime import datetime
from typing import Any

class SecureAgentMemory:
    def __init__(self, agent_id: str, session_id: str):
        self.agent_id = agent_id
        self.session_id = session_id
        self._store: dict = {}
        self._audit_log: list = []

    def _key(self, name: str) -> str:
        return f"{self.agent_id}:{self.session_id}:{name}"

    def set(self, name: str, value: Any, source: str = "agent") -> None:
        if source not in ("agent", "system"):
            raise PermissionError(f"Fuente no autorizada: {source}")
        checksum = hashlib.sha256(json.dumps(value, sort_keys=True).encode()).hexdigest()[:16]
        self._store[self._key(name)] = {"value": value, "source": source, "checksum": checksum}
        self._audit_log.append({"action": "set", "key": name, "source": source})

    def get(self, name: str) -> Any:
        entry = self._store.get(self._key(name))
        if entry is None:
            return None
        expected = hashlib.sha256(json.dumps(entry["value"], sort_keys=True).encode()).hexdigest()[:16]
        if expected != entry["checksum"]:
            raise RuntimeError(f"Integridad comprometida para: {name}")
        return entry["value"]

