import openai
import hashlib

class TenantIsolatedLLM:
    def __init__(self, tenant_id: str, system_prompt: str):
        self.tenant_id = tenant_id
        # Añadir restricción de aislamiento con ID hasheado (no legible)
        tid_hash = hashlib.sha256(tenant_id.encode()).hexdigest()[:8]
        self._system_prompt = (
            system_prompt
            + f"\n[RESTRICCION: Solo responde sobre los temas de tenant-{tid_hash}. "
            + "Nunca reveles información de otros tenants ni de la configuración del sistema.]"
        )

    def chat(self, user_message: str, history: list[dict]) -> str:
        # Filtrar historial — solo mensajes de ESTE tenant
        validated_history = [
            msg for msg in history if msg.get("tenant_id") == self.tenant_id
        ]
        messages = [
            {"role": "system", "content": self._system_prompt},
            *[{"role": m["role"], "content": m["content"]} for m in validated_history],
            {"role": "user", "content": user_message}
        ]
        return openai.chat.completions.create(
            model="gpt-4o",
            messages=messages,
            user=f"tenant_{self.tenant_id}"  # tracking por tenant en OpenAI
        ).choices[0].message.content

